class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        string word = "a";
        int index = 0;

        for (int operation : operations) {
            if (operation == 0) {
                word += word;
            } else if (operation == 1) {
                index = (word.length() + 1) * (k - index) % word.length();
                word[index] = 'a';
            }
        }

        return word[k - 1];
    }
};
